// ============================================================
// SELAROM - CALCULADORA DE REFORMA
// Tally webhook: array de {key, label, value, options, type}
// ============================================================

const fields = $input.first().json.body.data.fields;

// Busca campo por fragmento de label (case-insensitive)
function getField(part) {
  return fields.find(f => f.label && f.label.toLowerCase().includes(part.toLowerCase()));
}

// Resuelve UUID(s) a texto para MULTIPLE_CHOICE / DROPDOWN
function resolveChoice(field) {
  if (!field || !field.value) return '';
  const chosen = Array.isArray(field.value) ? field.value : [field.value];
  const opts = field.options || [];
  return chosen.map(uuid => {
    const o = opts.find(x => x.id === uuid);
    return o ? o.text.trim() : uuid;
  }).join(', ');
}

// Lee checkbox expandido: true/false
function isChecked(part) {
  const f = getField(part);
  return f && (f.value === true || f.value === 'true');
}

// Extrae primer numero de texto
function extractNum(text) {
  if (!text) return 0;
  if (text.toLowerCase().includes('no hace falta') || text.toLowerCase().includes('ninguna')) return 0;
  const m = text.match(/(\d+)/);
  return m ? parseInt(m[1], 10) : 0;
}

// Tablas €/m²
const GAS_TABLE     = [{max_m2:50,val:112.50},{max_m2:70,val:91.67},{max_m2:90,val:81.25},{max_m2:110,val:74.00},{max_m2:130,val:68.75},{max_m2:150,val:64.29},{max_m2:170,val:60.31},{max_m2:99999,val:56.67}];
const CONDUCTOS_TABLE = [{max_m2:50,val:137.50},{max_m2:70,val:106.67},{max_m2:90,val:97.50},{max_m2:110,val:97.00},{max_m2:130,val:95.83},{max_m2:150,val:96.43},{max_m2:170,val:97.50},{max_m2:99999,val:97.22}];
const ELEC_TABLE    = [{max_m2:50,val:125.00},{max_m2:70,val:91.67},{max_m2:90,val:82.50},{max_m2:110,val:78.00},{max_m2:130,val:73.75},{max_m2:150,val:75.00},{max_m2:170,val:73.75},{max_m2:99999,val:73.89}];
function tv(table, m2) { for (const r of table) if (m2 <= r.max_m2) return r.val; return table[table.length-1].val; }

// ---- LECTURAS ----
const uso_vivienda   = resolveChoice(getField('1. Uso de la vivienda'));
const vivienda_propia = resolveChoice(getField('2. ¿Vivienda en propiedad?'));

const tipo_propiedad_text = resolveChoice(getField('3. Tipo de propiedad')) || 'Piso';
let mult_tipo = tipo_propiedad_text.toLowerCase().includes('casa') ? 1.10 : 1.00;

const sup_text = resolveChoice(getField('4. Superficie del espacio'));
let numero_m2 = 70;
if (sup_text.includes('Menos de 50')) numero_m2 = 50;
else if (sup_text.includes('50 y 70'))   numero_m2 = 70;
else if (sup_text.includes('70 y 90'))   numero_m2 = 90;
else if (sup_text.includes('90 y 110'))  numero_m2 = 110;
else if (sup_text.includes('110 y 130')) numero_m2 = 130;
else if (sup_text.includes('130 y 150')) numero_m2 = 150;
else if (sup_text.includes('150 y 170')) numero_m2 = 170;
else if (sup_text.includes('170'))       numero_m2 = 190;

const distrib_text = resolveChoice(getField('5. ¿Quieres cambiar la distribución?'));
let mult_distrib = 1.00;
if (distrib_text.toLowerCase().includes('total'))   mult_distrib = 1.15;
else if (distrib_text.toLowerCase().includes('parcial')) mult_distrib = 1.05;

// ---- ADJUNTOS ----
function parseAdjunto(field) {
  if (!field || !field.value) return null;
  const val = Array.isArray(field.value) ? field.value[0] : field.value;
  if (!val || !val.url) return null;
  return { nombre: val.name || 'adjunto', url: val.url, tipo: val.mimeType || '', size_kb: val.size ? Math.round(val.size / 1024) : 0 };
}

const planos_adj = parseAdjunto(getField('6. ¿Tienes planos?'));
const fotos_adj  = parseAdjunto(getField('7. ¿Tienes fotos'));
const planos_str = planos_adj ? planos_adj.nombre : 'No adjunta';
const fotos_str  = fotos_adj  ? fotos_adj.nombre  : 'No adjunta';
const planos_url = planos_adj ? planos_adj.url    : '';
const fotos_url  = fotos_adj  ? fotos_adj.url     : '';

// ---- BAÑOS ----
const banos_text = resolveChoice(getField('8. Cuartos de baño'));
let n_banos = banos_text.includes('5 o más') ? 5 : extractNum(banos_text);
const precio_banos = n_banos * 7000;

// ---- COCINAS ----
const cocinas_text = resolveChoice(getField('9. Cocinas'));
let n_cocinas = cocinas_text.includes('3 o más') ? 3 : extractNum(cocinas_text);
const precio_cocinas = n_cocinas * 13500;

// ---- PUERTAS ----
const puertas_text = resolveChoice(getField('10. Puertas'));
let n_puertas = 0;
if (!puertas_text.toLowerCase().includes('no hace falta'))
  n_puertas = puertas_text.includes('15 puertas o más') ? 15 : extractNum(puertas_text);
const precio_puertas = n_puertas * 550;

// ---- VENTANAS ----
const ventanas_text = resolveChoice(getField('11. ¿Cuántas ventanas'));
let n_ventanas = ventanas_text.toLowerCase().includes('ninguna') ? 0 : (ventanas_text.includes('5 ventanas o más') ? 5 : extractNum(ventanas_text));
const precio_ventanas = n_ventanas * 1200;

// ---- BALCONERAS ----
const balconeras_text = resolveChoice(getField('12. ¿Cuántas balconeras'));
let n_balconeras = balconeras_text.toLowerCase().includes('ninguna') ? 0 : (balconeras_text.includes('4 balconeras o más') ? 4 : extractNum(balconeras_text));
const precio_balconeras = n_balconeras * 1700;

// ---- CLIMATIZACIÓN ----
let precio_clima = 0;
const clima_sel = [];
const fmt = n => n.toLocaleString('es-ES') + ' €';

if (isChecked('13. Climatización  (Calefacción de gas natural completa)')) { 
  const p = Math.round(numero_m2 * tv(GAS_TABLE, numero_m2));
  clima_sel.push(`Gas natural: ${fmt(p)}`); 
  precio_clima += p; 
}
if (isChecked('13. Climatización  (Radiadores eléctricos)')) { 
  const p = Math.round(numero_m2 * 22);
  clima_sel.push(`Radiadores eléctricos: ${fmt(p)}`); 
  precio_clima += p; 
}
if (isChecked('13. Climatización  (Aire acondicionado con splits)')) { 
  const p = Math.round(numero_m2 * 60);
  clima_sel.push(`Splits: ${fmt(p)}`); 
  precio_clima += p; 
}
if (isChecked('13. Climatización  (Climatización por conductos')) { 
  const p = Math.round(numero_m2 * tv(CONDUCTOS_TABLE, numero_m2));
  clima_sel.push(`Conductos: ${fmt(p)}`); 
  precio_clima += p; 
}
if (isChecked('13. Climatización  (Mantener')) { clima_sel.push('Mantener sistema actual'); }
if (isChecked('13. Climatización  (No lo sé')) { clima_sel.push('Necesita asesoramiento'); }

// ---- OTROS EXTRAS ----
let precio_electricidad = 0, precio_falsos_techos = 0, precio_alisado_paredes = 0, precio_pintura = 0;
const otros_sel = [];
if (isChecked('14. Otros (Electricidad completa)')) { 
  precio_electricidad = Math.round(numero_m2 * tv(ELEC_TABLE, numero_m2));
  otros_sel.push(`Electricidad completa: ${fmt(precio_electricidad)}`); 
}
if (isChecked('14. Otros (Falsos techos)')) { 
  precio_falsos_techos = Math.round(numero_m2 * 55);
  otros_sel.push(`Falsos techos: ${fmt(precio_falsos_techos)}`); 
}
if (isChecked('14. Otros (Alisar paredes)')) { 
  precio_alisado_paredes = Math.round(numero_m2 * 21);
  otros_sel.push(`Alisar paredes: ${fmt(precio_alisado_paredes)}`); 
}
if (isChecked('14. Otros (Pintura)')) { 
  precio_pintura = Math.round(numero_m2 * 9);
  otros_sel.push(`Pintura: ${fmt(precio_pintura)}`); 
}
if (isChecked('14. Otros (Fontanería completa)')) { otros_sel.push('Fontanería completa'); }
const extras_otros = precio_electricidad + precio_falsos_techos + precio_alisado_paredes + precio_pintura;

// ---- SUELOS ----
const suelos_text = resolveChoice(getField('15. ¿Quieres cambiar suelos?'));
let precio_suelos = 0;
if (suelos_text.toLowerCase().includes('parquet') || suelos_text.toLowerCase().includes('laminado')) precio_suelos = numero_m2 * 50;
else if (suelos_text.toLowerCase().includes('cer') || suelos_text.toLowerCase().includes('porcel')) precio_suelos = numero_m2 * 57;

// ---- CONTACTO Y CONTEXTO ----
const inv_f   = getField('inversión tienes prevista');   const inversion_prevista = inv_f   ? String(inv_f.value   || '') : '';
const fecha_f = getField('fecha te gustaría');           const fecha_inicio        = fecha_f ? String(fecha_f.value || '') : '';
const nom_f   = getField('Nombre');                      const nombre              = nom_f   ? String(nom_f.value   || '') : '';
const tel_f   = getField('Teléfono');                    const telefono            = tel_f   ? String(tel_f.value   || '') : '';
const email_f = getField('Email');                       const email_cliente       = email_f ? String(email_f.value || '') : '';
const dir_f   = getField('Dirección');                   const direccion           = dir_f   ? String(dir_f.value   || '') : '';
const tel_wa  = telefono.replace(/\D/g, '');

// ---- CÁLCULO FINAL ----
const subtotal_base  = precio_banos + precio_cocinas + precio_puertas + precio_ventanas + precio_balconeras + precio_clima + extras_otros + precio_suelos;
const ajuste_tipo    = subtotal_base * (mult_tipo - 1);
const ajuste_distrib = subtotal_base * (mult_distrib - 1);
const total          = Math.round(subtotal_base + ajuste_tipo + ajuste_distrib);

return [{ json: {
  nombre, telefono, tel_wa, email_cliente, direccion,
  uso_vivienda, vivienda_propia, inversion_prevista, fecha_inicio,
  planos: planos_str, planos_url, fotos: fotos_str, fotos_url,
  tipo_propiedad: tipo_propiedad_text, numero_m2, distribucion: distrib_text,
  n_banos, n_cocinas, n_puertas, n_ventanas, n_balconeras,
  climatizacion: clima_sel.join('<br>') || 'Ninguno',
  otros_extras: otros_sel.join('<br>') || 'Ninguno',
  suelos: suelos_text || 'No',
  mult_tipo, mult_distrib,
  precio_banos, precio_cocinas, precio_puertas, precio_ventanas, precio_balconeras,
  precio_clima: Math.round(precio_clima),
  precio_electricidad: Math.round(precio_electricidad),
  precio_falsos_techos, precio_alisado_paredes, precio_pintura,
  precio_suelos, extras_otros: Math.round(extras_otros),
  subtotal_base: Math.round(subtotal_base), ajuste_tipo: Math.round(ajuste_tipo), ajuste_distrib: Math.round(ajuste_distrib),
  total_estimado: total, total_estimado_str: fmt(total)
}}];
